'use client';

import Link from 'next/link';
import { ShoppingBag, ArrowRight } from 'lucide-react';
import { useCartStore } from '@/store';
import { CartItem, CartSummary } from '@/components/cart';
import { Button } from '@/components/ui';

export default function CartPage() {
  const { items, getSubtotal, getShipping, getTax, getTotal, getItemCount } = useCartStore();

  const itemCount = getItemCount();
  const subtotal = getSubtotal();
  const shipping = getShipping();
  const tax = getTax();
  const total = getTotal();

  if (items.length === 0) {
    return (
      <div className="min-h-[60vh] flex items-center justify-center py-16">
        <div className="text-center max-w-md mx-auto px-4">
          <div className="mb-6 rounded-full bg-gray-100 dark:bg-dark-elevated p-8 inline-flex">
            <ShoppingBag className="h-16 w-16 text-gray-400" />
          </div>
          <h1 className="text-2xl font-bold mb-3">Your cart is empty</h1>
          <p className="text-gray-500 dark:text-gray-400 mb-8">
            Looks like you haven't added any items to your cart yet. 
            Start exploring our products to find something you'll love.
          </p>
          <Link href="/products">
            <Button size="lg" rightIcon={<ArrowRight className="h-5 w-5" />}>
              Start Shopping
            </Button>
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen py-8">
      <div className="mx-auto max-w-7xl px-4 sm:px-6">
        <h1 className="text-3xl font-bold mb-8">Shopping Cart ({itemCount})</h1>

        <div className="flex flex-col lg:flex-row gap-8">
          <div className="flex-1">
            <div className="space-y-4">
              {items.map((item) => (
                <CartItem key={item.product.id} item={item} />
              ))}
            </div>

            <div className="mt-8 flex items-center justify-between">
              <Link href="/products">
                <Button variant="ghost" leftIcon={<ArrowRight className="h-4 w-4 rotate-180" />}>
                  Continue Shopping
                </Button>
              </Link>
            </div>
          </div>

          <div className="lg:w-96">
            <CartSummary
              subtotal={subtotal}
              shipping={shipping}
              tax={tax}
              total={total}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useParams } from 'next/navigation';
import { useProductsByCategory, useCategories } from '@/hooks';
import { ProductGrid, ProductFilters } from '@/components/product';
import { SkeletonProductGrid, Select, Button } from '@/components/ui';
import { SORT_OPTIONS, CATEGORIES } from '@/lib/constants';
import { ChevronRight } from 'lucide-react';
import Link from 'next/link';

export default function CategoryPage() {
  const params = useParams();
  const slug = params.slug as string;

  const [page, setPage] = useState(1);
  const [sortBy, setSortBy] = useState('popular');
  const limit = 12;

  const { data, isLoading } = useProductsByCategory(slug, limit, (page - 1) * limit);

  const category = CATEGORIES.find(c => c.slug === slug) || { name: slug.replace('-', ' '), slug };

  return (
    <div className="min-h-screen py-8">
      <div className="mx-auto max-w-7xl px-4 sm:px-6">
        <nav className="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400 mb-6">
          <Link href="/" className="hover:text-accent">Home</Link>
          <ChevronRight className="h-4 w-4" />
          <span className="text-gray-900 dark:text-dark-text capitalize">
            {category.name.replace('-', ' ')}
          </span>
        </nav>

        <div className="flex flex-col lg:flex-row gap-8">
          <ProductFilters
            filters={{ category: slug }}
            onFilterChange={() => {}}
            categories={CATEGORIES.map(c => ({ slug: c.slug, name: c.name }))}
          />

          <div className="flex-1">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-6">
              <div>
                <h1 className="text-2xl font-bold capitalize">{category.name.replace('-', ' ')}</h1>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                  {data?.total || 0} products
                </p>
              </div>
              <Select
                options={SORT_OPTIONS}
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="w-48"
              />
            </div>

            {isLoading ? (
              <SkeletonProductGrid count={8} />
            ) : (
              <ProductGrid products={data?.data || []} columns={3} />
            )}

            {data && data.totalPages > 1 && (
              <div className="flex items-center justify-center gap-2 mt-12">
                <Button
                  variant="outline"
                  onClick={() => setPage(p => Math.max(1, p - 1))}
                  disabled={page === 1}
                >
                  Previous
                </Button>
                <span className="px-4 text-sm">
                  Page {page} of {data.totalPages}
                </span>
                <Button
                  variant="outline"
                  onClick={() => setPage(p => Math.min(data.totalPages, p + 1))}
                  disabled={page === data.totalPages}
                >
                  Next
                </Button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import Link from 'next/link';
import { ArrowLeft, CreditCard, Check } from 'lucide-react';
import { useCartStore } from '@/store';
import { ShippingForm, PaymentForm, CheckoutSteps } from '@/components/checkout';
import { Button, Card, CardContent } from '@/components/ui';
import { formatPrice } from '@/lib/utils';

type CheckoutStep = 'shipping' | 'payment' | 'review';

export default function CheckoutPage() {
  const router = useRouter();
  const { items, getSubtotal, getShipping, getTax, getTotal, clearCart } = useCartStore();

  const [currentStep, setCurrentStep] = useState<CheckoutStep>('shipping');
  const [shippingAddress, setShippingAddress] = useState<any>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const subtotal = getSubtotal();
  const shipping = getShipping();
  const tax = getTax();
  const total = getTotal();

  const handleShippingSubmit = (data: any) => {
    setShippingAddress(data);
    setCurrentStep('payment');
  };

  const handlePaymentSubmit = async () => {
    setIsProcessing(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsProcessing(false);
    setCurrentStep('review');
  };

  const handlePlaceOrder = async () => {
    setIsProcessing(true);
    await new Promise(resolve => setTimeout(resolve, 2000));
    clearCart();
    setIsProcessing(false);
    router.push('/checkout/success');
  };

  if (items.length === 0) {
    return (
      <div className="min-h-[60vh] flex items-center justify-center py-16">
        <div className="text-center max-w-md mx-auto px-4">
          <h1 className="text-2xl font-bold mb-4">Your cart is empty</h1>
          <p className="text-gray-500 dark:text-gray-400 mb-8">
            Add items to your cart before checking out.
          </p>
          <Link href="/products">
            <Button>Start Shopping</Button>
          </Link>
        </div>
      </div>
    );
  }

  const stepIndex = currentStep === 'shipping' ? 0 : currentStep === 'payment' ? 1 : 2;

  return (
    <div className="min-h-screen py-8 bg-background-alt dark:bg-dark-background">
      <div className="mx-auto max-w-7xl px-4 sm:px-6">
        <Link
          href="/cart"
          className="inline-flex items-center gap-2 text-sm text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 mb-6"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Cart
        </Link>

        <h1 className="text-3xl font-bold mb-8">Checkout</h1>

        <CheckoutSteps currentStep={stepIndex} />

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">
            {currentStep === 'shipping' && (
              <Card>
                <CardContent className="p-6 sm:p-8">
                  <h2 className="text-xl font-semibold mb-6 flex items-center gap-2">
                    <span className="flex items-center justify-center w-8 h-8 rounded-full bg-accent text-white text-sm font-bold">
                      1
                    </span>
                    Shipping Address
                  </h2>
                  <ShippingForm onSubmit={handleShippingSubmit} defaultValues={shippingAddress} />
                </CardContent>
              </Card>
            )}

            {currentStep === 'payment' && (
              <Card>
                <CardContent className="p-6 sm:p-8">
                  <h2 className="text-xl font-semibold mb-6 flex items-center gap-2">
                    <span className="flex items-center justify-center w-8 h-8 rounded-full bg-accent text-white text-sm font-bold">
                      2
                    </span>
                    Payment Method
                  </h2>
                  <PaymentForm onSubmit={handlePaymentSubmit} isProcessing={isProcessing} />

                  <div className="mt-6 pt-6 border-t border-gray-200 dark:border-dark-border">
                    <Button
                      variant="outline"
                      onClick={() => setCurrentStep('shipping')}
                    >
                      Back to Shipping
                    </Button>
                  </div>
                </CardContent>
              </Card>
            )}

            {currentStep === 'review' && (
              <div className="space-y-6">
                <Card>
                  <CardContent className="p-6 sm:p-8">
                    <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
                      <Check className="h-5 w-5 text-success" />
                      Review Your Order
                    </h2>

                    <div className="space-y-4">
                      <div>
                        <h3 className="font-medium text-sm text-gray-500 dark:text-gray-400 mb-1">
                          Shipping Address
                        </h3>
                        <p>
                          {shippingAddress?.firstName} {shippingAddress?.lastName}
                        </p>
                        <p>{shippingAddress?.street}</p>
                        {shippingAddress?.apartment && <p>{shippingAddress?.apartment}</p>}
                        <p>
                          {shippingAddress?.city}, {shippingAddress?.state} {shippingAddress?.zipCode}
                        </p>
                        <p>{shippingAddress?.country}</p>
                        <p>{shippingAddress?.phone}</p>
                      </div>

                      <div>
                        <h3 className="font-medium text-sm text-gray-500 dark:text-gray-400 mb-1">
                          Payment Method
                        </h3>
                        <div className="flex items-center gap-2">
                          <CreditCard className="h-4 w-4" />
                          <span>Credit Card ending in 4242</span>
                        </div>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardContent className="p-6 sm:p-8">
                    <h3 className="font-semibold mb-4">Order Items</h3>
                    <div className="space-y-4">
                      {items.map((item) => (
                        <div key={item.product.id} className="flex gap-4">
                          <div className="relative h-16 w-16 flex-shrink-0 overflow-hidden rounded-lg bg-gray-100 dark:bg-dark-elevated">
                            <Image
                              src={item.product.image}
                              alt={item.product.title}
                              fill
                              className="object-cover"
                            />
                          </div>
                          <div className="flex-1">
                            <p className="font-medium line-clamp-1">{item.product.title}</p>
                            <p className="text-sm text-gray-500">Qty: {item.quantity}</p>
                          </div>
                          <p className="font-semibold">
                            {formatPrice(item.product.price * item.quantity)}
                          </p>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>

                <div className="flex gap-4">
                  <Button
                    variant="outline"
                    onClick={() => setCurrentStep('payment')}
                    disabled={isProcessing}
                  >
                    Back to Payment
                  </Button>
                  <Button
                    onClick={handlePlaceOrder}
                    isLoading={isProcessing}
                    className="flex-1"
                  >
                    Place Order - {formatPrice(total)}
                  </Button>
                </div>
              </div>
            )}
          </div>

          <div className="lg:col-span-1">
            <Card className="sticky top-24">
              <CardContent className="p-6">
                <h2 className="font-semibold mb-4">Order Summary</h2>

                <div className="space-y-3 text-sm">
                  <div className="flex justify-between">
                    <span className="text-gray-500">Items ({items.length})</span>
                    <span>{formatPrice(subtotal)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Shipping</span>
                    <span className={shipping === 0 ? 'text-success' : ''}>
                      {shipping === 0 ? 'FREE' : formatPrice(shipping)}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Tax</span>
                    <span>{formatPrice(tax)}</span>
                  </div>
                  <div className="border-t border-gray-200 dark:border-dark-border pt-3 flex justify-between font-semibold text-lg">
                    <span>Total</span>
                    <span>{formatPrice(total)}</span>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useParams, notFound } from 'next/navigation';
import Image from 'next/image';
import Link from 'next/link';
import { Heart, ShoppingCart, Truck, Shield, RefreshCw, ChevronRight, ChevronLeft, Star, Minus, Plus } from 'lucide-react';
import { useProduct, useProductsByCategory } from '@/hooks';
import { useCartStore, useWishlistStore } from '@/store';
import { Button, Badge, Rating, Skeleton, Card } from '@/components/ui';
import { ProductGrid } from '@/components/product';
import { formatPrice, calculateDiscount, cn } from '@/lib/utils';

export default function ProductDetailPage() {
  const params = useParams();
  const productId = params.id as string;

  const { data: product, isLoading, error } = useProduct(productId);
  const [selectedImage, setSelectedImage] = useState(0);
  const [quantity, setQuantity] = useState(1);

  const { addItem } = useCartStore();
  const { isInWishlist, toggleItem } = useWishlistStore();

  const isWishlisted = product ? isInWishlist(product.id) : false;

  const { data: relatedProducts } = useProductsByCategory(
    product?.category || '',
    4,
    0
  );

  if (isLoading) {
    return (
      <div className="min-h-screen py-8">
        <div className="mx-auto max-w-7xl px-4 sm:px-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            <div className="space-y-4">
              <Skeleton className="h-96 w-full rounded-xl" />
              <div className="grid grid-cols-4 gap-4">
                {[1, 2, 3, 4].map(i => (
                  <Skeleton key={i} className="h-24 w-full rounded-lg" />
                ))}
              </div>
            </div>
            <div className="space-y-6">
              <Skeleton className="h-8 w-3/4" />
              <Skeleton className="h-6 w-1/4" />
              <Skeleton className="h-12 w-1/3" />
              <Skeleton className="h-32 w-full" />
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold mb-4">Product Not Found</h1>
          <Link href="/products">
            <Button>Browse Products</Button>
          </Link>
        </div>
      </div>
    );
  }

  const images = product.images || [product.image];
  const discount = product.originalPrice
    ? calculateDiscount(product.originalPrice, product.price)
    : 0;

  const handleAddToCart = () => {
    addItem(product, quantity);
  };

  const handleToggleWishlist = () => {
    toggleItem(product);
  };

  return (
    <div className="min-h-screen py-8">
      <div className="mx-auto max-w-7xl px-4 sm:px-6">
        <nav className="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400 mb-6">
          <Link href="/" className="hover:text-accent">Home</Link>
          <ChevronRight className="h-4 w-4" />
          <Link href="/products" className="hover:text-accent">Products</Link>
          <ChevronRight className="h-4 w-4" />
          <Link href={`/products?category=${product.category}`} className="hover:text-accent capitalize">
            {product.category.replace('-', ' ')}
          </Link>
          <ChevronRight className="h-4 w-4" />
          <span className="text-gray-900 dark:text-dark-text truncate max-w-[200px]">
            {product.title}
          </span>
        </nav>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          <div className="space-y-4">
            <div className="relative aspect-square overflow-hidden rounded-xl bg-gray-100 dark:bg-dark-elevated">
              <Image
                src={images[selectedImage]}
                alt={product.title}
                fill
                className="object-cover"
                priority
              />
              {discount > 0 && (
                <Badge variant="error" className="absolute top-4 left-4">
                  -{discount}% OFF
                </Badge>
              )}
            </div>

            {images.length > 1 && (
              <div className="grid grid-cols-4 gap-4">
                {images.map((img, index) => (
                  <button
                    key={index}
                    onClick={() => setSelectedImage(index)}
                    className={cn(
                      'relative aspect-square overflow-hidden rounded-lg border-2 transition-colors',
                      selectedImage === index
                        ? 'border-accent'
                        : 'border-transparent hover:border-gray-300'
                    )}
                  >
                    <Image
                      src={img}
                      alt={`${product.title} - ${index + 1}`}
                      fill
                      className="object-cover"
                    />
                  </button>
                ))}
              </div>
            )}
          </div>

          <div className="space-y-6">
            <div>
              <p className="text-sm text-gray-500 dark:text-gray-400 uppercase tracking-wide mb-2">
                {product.category}
              </p>
              <h1 className="text-3xl font-bold">{product.title}</h1>
            </div>

            <div className="flex items-center gap-4">
              <Rating rating={product.rating} reviewCount={product.reviewCount} />
              <span className="text-sm text-gray-500 dark:text-gray-400">
                {product.reviewCount.toLocaleString()} reviews
              </span>
            </div>

            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-bold text-gray-900 dark:text-dark-text">
                {formatPrice(product.price)}
              </span>
              {product.originalPrice && (
                <>
                  <span className="text-xl text-gray-400 line-through">
                    {formatPrice(product.originalPrice)}
                  </span>
                  <Badge variant="success">Save {formatPrice(product.originalPrice - product.price)}</Badge>
                </>
              )}
            </div>

            <p className="text-gray-600 dark:text-gray-400 leading-relaxed">
              {product.description}
            </p>

            <div className="flex items-center gap-4">
              <div className="flex items-center border border-gray-300 dark:border-dark-border rounded-lg">
                <button
                  onClick={() => setQuantity(q => Math.max(1, q - 1))}
                  className="p-3 hover:bg-gray-100 dark:hover:bg-dark-elevated transition-colors"
                >
                  <Minus className="h-4 w-4" />
                </button>
                <input
                  type="number"
                  value={quantity}
                  onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                  className="w-16 text-center border-x border-gray-300 dark:border-dark-border py-2"
                  min="1"
                  max={product.stockCount}
                />
                <button
                  onClick={() => setQuantity(q => Math.min(product.stockCount, q + 1))}
                  className="p-3 hover:bg-gray-100 dark:hover:bg-dark-elevated transition-colors"
                >
                  <Plus className="h-4 w-4" />
                </button>
              </div>
              <span className="text-sm text-gray-500 dark:text-gray-400">
                {product.stockCount} in stock
              </span>
            </div>

            <div className="flex gap-4">
              <Button
                size="lg"
                className="flex-1"
                onClick={handleAddToCart}
                disabled={!product.inStock}
                leftIcon={<ShoppingCart className="h-5 w-5" />}
              >
                {product.inStock ? 'Add to Cart' : 'Out of Stock'}
              </Button>
              <Button
                size="lg"
                variant="outline"
                onClick={handleToggleWishlist}
                className={cn(isWishlisted && 'text-error border-error')}
              >
                <Heart className={cn('h-5 w-5', isWishlisted && 'fill-current')} />
              </Button>
            </div>

            <Card className="mt-8">
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="flex items-center gap-3 p-4">
                  <Truck className="h-6 w-6 text-accent" />
                  <div>
                    <p className="font-medium text-sm">Free Shipping</p>
                    <p className="text-xs text-gray-500">Orders over $50</p>
                  </div>
                </div>
                <div className="flex items-center gap-3 p-4">
                  <Shield className="h-6 w-6 text-accent" />
                  <div>
                    <p className="font-medium text-sm">Secure Payment</p>
                    <p className="text-xs text-gray-500">100% Protected</p>
                  </div>
                </div>
                <div className="flex items-center gap-3 p-4">
                  <RefreshCw className="h-6 w-6 text-accent" />
                  <div>
                    <p className="font-medium text-sm">Easy Returns</p>
                    <p className="text-xs text-gray-500">30-day policy</p>
                  </div>
                </div>
              </div>
            </Card>
          </div>
        </div>

        {relatedProducts && relatedProducts.data.length > 0 && (
          <section className="mt-16">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-2xl font-bold">Related Products</h2>
              <Link href={`/products?category=${product.category}`}>
                <Button variant="ghost">View All</Button>
              </Link>
            </div>
            <ProductGrid products={relatedProducts.data} columns={4} />
          </section>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, Suspense } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { ChevronRight } from 'lucide-react';
import { useProducts, useCategories } from '@/hooks';
import { ProductGrid, ProductFilters } from '@/components/product';
import { Button, Select, SkeletonProductGrid } from '@/components/ui';
import { SORT_OPTIONS, CATEGORIES, getCategoryBySlug } from '@/lib/constants';
import { cn } from '@/lib/utils';

function ProductsContent() {
  const router = useRouter();
  const searchParams = useSearchParams();

  const [page, setPage] = useState(1);
  const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'popular');
  const filters = {
    category: searchParams.get('category') || undefined,
    minPrice: searchParams.get('minPrice') ? Number(searchParams.get('minPrice')) : undefined,
    maxPrice: searchParams.get('maxPrice') ? Number(searchParams.get('maxPrice')) : undefined,
    minRating: searchParams.get('minRating') ? Number(searchParams.get('minRating')) : undefined,
  };

  const limit = 12;
  const { data, isLoading, isError, refetch } = useProducts(
    limit,
    (page - 1) * limit,
    {
      category: filters.category,
      minPrice: filters.minPrice,
      maxPrice: filters.maxPrice,
      minRating: filters.minRating,
      sortBy: sortBy as any,
    }
  );

  const categories = CATEGORIES.map(c => ({ slug: c.slug, name: c.name }));
  const currentCategory = filters.category ? getCategoryBySlug(filters.category) : null;

  const handleFilterChange = (newFilters: { category?: string; minPrice?: number; maxPrice?: number; minRating?: number }) => {
    const params = new URLSearchParams();
    if (newFilters.category) params.set('category', newFilters.category);
    if (newFilters.minPrice) params.set('minPrice', String(newFilters.minPrice));
    if (newFilters.maxPrice) params.set('maxPrice', String(newFilters.maxPrice));
    if (newFilters.minRating) params.set('minRating', String(newFilters.minRating));
    if (sortBy && sortBy !== 'popular') params.set('sort', sortBy);

    router.push(`/products?${params.toString()}`, { scroll: false });
    setPage(1);
  };

  return (
    <div className="min-h-screen py-8">
      <div className="mx-auto max-w-7xl px-4 sm:px-6">
        <nav className="flex items-center gap-2 text-sm text-[var(--muted-foreground)] mb-6">
          <a href="/" className="hover:text-[#ff9900]">Home</a>
          <ChevronRight className="h-4 w-4" />
          <span className="text-[var(--card-foreground)]">
            {currentCategory?.name || 'All Products'}
          </span>
        </nav>

        <div className="flex flex-col lg:flex-row gap-8">
          <ProductFilters
            filters={filters}
            onFilterChange={handleFilterChange}
            categories={categories}
          />

          <div className="flex-1">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-6">
              <div>
                <h1 className="text-2xl font-bold text-[var(--card-foreground)]">
                  {currentCategory?.name || 'All Products'}
                </h1>
                <p className="text-sm text-[var(--muted-foreground)] mt-1">
                  {data?.total || 0} products
                </p>
              </div>

              <div className="flex items-center gap-4">
                <Select
                  options={SORT_OPTIONS}
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value)}
                  className="w-48"
                />
              </div>
            </div>

            {isLoading ? (
              <SkeletonProductGrid count={8} />
            ) : (
              <ProductGrid
                products={data?.data || []}
                isError={isError}
                onRetry={() => refetch()}
                columns={3}
              />
            )}

            {data && data.totalPages > 1 && (
              <div className="flex items-center justify-center gap-2 mt-12">
                <Button
                  variant="outline"
                  onClick={() => setPage(p => Math.max(1, p - 1))}
                  disabled={page === 1}
                >
                  Previous
                </Button>
                <div className="flex items-center gap-1">
                  {Array.from({ length: Math.min(5, data.totalPages) }).map((_, i) => {
                    let pageNum;
                    if (data.totalPages <= 5) {
                      pageNum = i + 1;
                    } else if (page <= 3) {
                      pageNum = i + 1;
                    } else if (page >= data.totalPages - 2) {
                      pageNum = data.totalPages - 4 + i;
                    } else {
                      pageNum = page - 2 + i;
                    }

                    return (
                      <button
                        key={i}
                        onClick={() => setPage(pageNum)}
                        className={cn(
                          'w-10 h-10 rounded-lg text-sm font-medium transition-colors',
                          page === pageNum
                            ? 'bg-[#ff9900] text-white'
                            : 'hover:bg-[var(--muted)] text-[var(--card-foreground)]'
                        )}
                      >
                        {pageNum}
                      </button>
                    );
                  })}
                </div>
                <Button
                  variant="outline"
                  onClick={() => setPage(p => Math.min(data.totalPages, p + 1))}
                  disabled={page === data.totalPages}
                >
                  Next
                </Button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

