                  <div className="absolute right-0 mt-2 w-56 rounded-xl border border-white/10 bg-secondary py-2 shadow-xl animate-fade-in">
                    <div className="px-4 py-2 border-b border-white/10">
                      <p className="font-medium">{user.name}</p>
                      <p className="text-sm text-white/60">{user.email}</p>
                    </div>
                    <Link
                      href="/orders"
                      className="flex items-center gap-3 px-4 py-2 text-sm hover:bg-white/10 transition-colors"
                      onClick={() => setIsUserMenuOpen(false)}
                    >
                      <Package className="h-4 w-4" />
