              type="submit"
              className="absolute right-3 top-1/2 -translate-y-1/2 text-white/60 hover:text-white"
            >
              <Search className="h-5 w-5" />
            </button>
          </form>
        </div>
      )}

      {isMenuOpen && (
        <div className="lg:hidden border-t border-white/10 py-4 animate-fade-in">
          <nav className="px-4 space-y-2">
            {['All Products', 'Electronics', 'Clothing', 'Home & Living', 'Accessories'].map(
              (item) => (
                <Link
                  key={item}
                  href={`/products${item !== 'All Products' ? `?category=${item.toLowerCase().replace(/ & /g, '-')}` : ''}`}
                  className="block py-2 text-sm hover:text-accent transition-colors"
                  onClick={() => setIsMenuOpen(false)}
                >
                  {item}
                </Link>
              )
            )}
          </nav>
        </div>
      )}
    </header>
  );
}

'use client';

import { useState } from 'react';
import { X, SlidersHorizontal } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui';
import { PRICE_RANGES, RATING_OPTIONS } from '@/lib/constants';

interface ProductFiltersProps {
  filters: {
    minPrice?: number;
    maxPrice?: number;
    minRating?: number;
    category?: string;
  };
  onFilterChange: (filters: ProductFiltersProps['filters']) => void;
  categories: { slug: string; name: string }[];
  className?: string;
}

export function ProductFilters({
  filters,
  onFilterChange,
  categories,
  className,
}: ProductFiltersProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [localFilters, setLocalFilters] = useState(filters);

  const handleApply = () => {
    onFilterChange(localFilters);
    setIsOpen(false);
  };

  const handleReset = () => {
    const resetFilters = {
      minPrice: undefined,
      maxPrice: undefined,
      minRating: undefined,
      category: undefined,
    };
    setLocalFilters(resetFilters);
    onFilterChange(resetFilters);
  };

  const handlePriceRangeChange = (range: typeof PRICE_RANGES[0] | null) => {
    if (range) {
      setLocalFilters({
        ...localFilters,
        minPrice: range.min,
        maxPrice: range.max === Infinity ? undefined : range.max,
      });
    } else {
      setLocalFilters({
        ...localFilters,
        minPrice: undefined,
        maxPrice: undefined,
      });
    }
  };

  const FilterContent = () => (
    <div className="space-y-6">
      <div>
        <h4 className="font-medium mb-3 text-[var(--card-foreground)]">Category</h4>
        <div className="space-y-2">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="category"
              checked={!localFilters.category}
              onChange={() =>
                setLocalFilters({ ...localFilters, category: undefined })
              }
              className="accent-[#ff9900]"
            />
            <span className="text-sm text-[var(--card-foreground)]">All Categories</span>
          </label>
          {categories.map((cat) => (
            <label key={cat.slug} className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                name="category"
                checked={localFilters.category === cat.slug}
                onChange={() =>
                  setLocalFilters({ ...localFilters, category: cat.slug })
                }
                className="accent-[#ff9900]"
              />
              <span className="text-sm text-[var(--card-foreground)]">{cat.name}</span>
            </label>
          ))}
        </div>
      </div>

      <div>
        <h4 className="font-medium mb-3 text-[var(--card-foreground)]">Price Range</h4>
        <div className="space-y-2">
          {PRICE_RANGES.map((range) => (
            <label key={range.label} className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                name="price"
                checked={
                  localFilters.minPrice === range.min &&
                  localFilters.maxPrice === range.max
                }
                onChange={() => handlePriceRangeChange(range)}
                className="accent-[#ff9900]"
              />
              <span className="text-sm text-[var(--card-foreground)]">{range.label}</span>
            </label>
          ))}
        </div>
      </div>

      <div>
        <h4 className="font-medium mb-3 text-[var(--card-foreground)]">Customer Rating</h4>
        <div className="space-y-2">
          {RATING_OPTIONS.map((opt) => (
            <label key={opt.value} className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                name="rating"
                checked={localFilters.minRating === opt.value}
                onChange={() =>
                  setLocalFilters({
                    ...localFilters,
                    minRating: opt.value,
                  })
                }
                className="accent-[#ff9900]"
              />
              <span className="text-sm text-[var(--card-foreground)]">{opt.label} & Up</span>
            </label>
          ))}
        </div>
      </div>

      <div className="flex gap-2 pt-4 border-t border-[var(--border)]">
        <Button variant="outline" onClick={handleReset} className="flex-1">
          Reset
        </Button>
        <Button onClick={handleApply} className="flex-1">
          Apply
        </Button>
      </div>
    </div>
  );

  return (
    <>
      <div className="hidden lg:block w-64 flex-shrink-0">
        <div className={cn('sticky top-24', className)}>
          <div className="rounded-xl border border-[var(--border)] bg-[var(--card)] p-6">
            <h3 className="font-semibold mb-4 text-[var(--card-foreground)]">Filters</h3>
            <FilterContent />
          </div>
        </div>
      </div>

      <div className="lg:hidden">
        <Button
          variant="outline"
          onClick={() => setIsOpen(true)}
          leftIcon={<SlidersHorizontal className="h-4 w-4" />}
        >
          Filters
        </Button>

        {isOpen && (
          <>
            <div
              className="fixed inset-0 z-50 bg-black/50"
              onClick={() => setIsOpen(false)}
            />
            <div className="fixed inset-x-4 bottom-0 z-50 rounded-t-2xl bg-[var(--card)] p-6 animate-slide-in max-h-[80vh] overflow-y-auto">
              <div className="flex items-center justify-between mb-4">
                <h3 className="font-semibold text-lg text-[var(--card-foreground)]">Filters</h3>
                <button
                  onClick={() => setIsOpen(false)}
                  className="p-2 hover:bg-[var(--muted)] rounded-lg text-[var(--card-foreground)]"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>
              <FilterContent />
            </div>
          </>
        )}
      </div>
    </>
  );
}

