'use client';

import { useState, useEffect, useCallback } from 'react';
import { debounce } from '@/lib/utils';

export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(timer);
    };
  }, [value, delay]);

  return debouncedValue;
}

export function useDebouncedCallback<T extends (...args: any[]) => any>(
  callback: T,
  delay: number
): (...args: Parameters<T>) => void {
  const debouncedCallback = useCallback(
    debounce(callback, delay),
    [callback, delay]
  );
  return debouncedCallback;
}

export function useLocalStorage<T>(
  key: string,
  initialValue: T
): [T, (value: T | ((val: T) => T)) => void] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    if (typeof window === 'undefined') {
      return initialValue;
    }
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(error);
      return initialValue;
    }
  });

  const setValue = (value: T | ((val: T) => T)) => {
    try {
      const valueToStore =
        value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      if (typeof window !== 'undefined') {
        window.localStorage.setItem(key, JSON.stringify(valueToStore));
      }
    } catch (error) {
      console.error(error);
    }
  };

  return [storedValue, setValue];
}

export function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(false);

  useEffect(() => {
    if (typeof window === 'undefined') return;

    const media = window.matchMedia(query);
    if (media.matches !== matches) {
      setMatches(media.matches);
    }

    const listener = () => setMatches(media.matches);
    media.addEventListener('change', listener);

    return () => media.removeEventListener('change', listener);
  }, [matches, query]);

  return matches;
}

export function useIsMobile(): boolean {
  return useMediaQuery('(max-width: 639px)');
}

export function useIsTablet(): boolean {
  return useMediaQuery('(min-width: 640px) and (max-width: 1023px)');
}

export function useIsDesktop(): boolean {
  return useMediaQuery('(min-width: 1024px)');
}

export function useScrollPosition() {
  const [scrollPosition, setScrollPosition] = useState(0);

  useEffect(() => {
    const updatePosition = () => {
      setScrollPosition(window.scrollY);
    };

    window.addEventListener('scroll', updatePosition);
    updatePosition();

    return () => window.removeEventListener('scroll', updatePosition);
  }, []);

  return scrollPosition;
}

import { Product, Category, PaginatedResponse, SearchFilters, User, Order, CartItem } from '@/types';
import { API_BASE_URL, getCategoryApiSlug } from '@/lib/constants';

class ApiService {
  private baseUrl: string;

  constructor(baseUrl: string) {
    this.baseUrl = baseUrl;
  }

  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${this.baseUrl}${endpoint}`, {
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
        ...options,
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.status} ${response.statusText}`);
      }

      return response.json();
    } catch (error) {
      console.error('API Request failed:', error);
      throw error;
    }
  }

  async getProducts(
    limit = 20,
    skip = 0,
    filters?: SearchFilters
  ): Promise<PaginatedResponse<Product>> {
    let url = `/products?limit=${limit}&skip=${skip}&select=title,price,thumbnail,rating,category,id,description,stock,discountPercentage,images,brand`;

    if (filters?.category) {
      const apiCategory = getCategoryApiSlug(filters.category);
      url += `&category=${encodeURIComponent(apiCategory)}`;
    }

    if (filters?.sortBy === 'price-asc') {
      url += '&sortBy=price&order=asc';
    } else if (filters?.sortBy === 'price-desc') {
      url += '&sortBy=price&order=desc';
    } else if (filters?.sortBy === 'rating') {
      url += '&sortBy=rating&order=desc';
    }

    try {
      const data = await this.request<{ products: Product[]; total: number }>(url);

      let products = data.products.map(p => this.transformProduct(p));

      if (filters?.minPrice) {
        products = products.filter(p => p.price >= filters.minPrice!);
      }
      if (filters?.maxPrice) {
        products = products.filter(p => p.price <= filters.maxPrice!);
      }
      if (filters?.minRating) {
        products = products.filter(p => p.rating >= filters.minRating!);
      }

      return {
        data: products,
        total: data.total,
        page: Math.floor(skip / limit) + 1,
        limit,
        totalPages: Math.ceil(data.total / limit),
      };
    } catch {
      return {
        data: [],
        total: 0,
        page: 1,
        limit,
        totalPages: 0,
      };
    }
  }

  async getProduct(id: string): Promise<Product> {
    const data = await this.request<any>(`/products/${id}`);
    return this.transformProduct(data);
  }

  async getProductsByCategory(category: string, limit = 20, skip = 0): Promise<PaginatedResponse<Product>> {
    const apiCategory = getCategoryApiSlug(category);

    try {
      const data = await this.request<{ products: Product[]; total: number }>(
        `/products/category/${encodeURIComponent(apiCategory)}?limit=${limit}&skip=${skip}`
      );

      return {
        data: data.products.map(p => this.transformProduct(p)),
        total: data.total,
        page: Math.floor(skip / limit) + 1,
        limit,
        totalPages: Math.ceil(data.total / limit),
      };
    } catch {
      return {
        data: [],
        total: 0,
        page: 1,
        limit,
        totalPages: 0,
      };
    }
  }

  async searchProducts(query: string, limit = 20, skip = 0): Promise<PaginatedResponse<Product>> {
    try {
      const data = await this.request<{ products: Product[]; total: number }>(
        `/products/search?q=${encodeURIComponent(query)}&limit=${limit}&skip=${skip}`
      );

      return {
        data: data.products.map(p => this.transformProduct(p)),
        total: data.total,
        page: Math.floor(skip / limit) + 1,
        limit,
        totalPages: Math.ceil(data.total / limit),
      };
    } catch {
      return {
        data: [],
        total: 0,
        page: 1,
        limit,
        totalPages: 0,
      };
    }
  }

  async getCategories(): Promise<Category[]> {
    const categories = await this.request<string[]>('/products/categories');
    return categories.map((name, index) => ({
      id: String(index + 1),
      name: this.formatCategoryName(name),
      slug: name,
      image: this.getCategoryImage(name),
    }));
  }

  private transformProduct(p: any): Product {
    const originalPrice = p.discountPercentage 
      ? Math.round(p.price / (1 - p.discountPercentage / 100))
      : undefined;

    const image = p.thumbnail || p.images?.[0] || '/placeholder.png';

    return {
      id: String(p.id),
      title: p.title,
      description: p.description || '',
      price: p.price,
      originalPrice,
      image,
      images: p.images && p.images.length > 0 ? p.images : [image],
      category: p.category,
      brand: p.brand,
      rating: p.rating || 4,
      reviewCount: Math.floor(Math.random() * 500) + 50,
      inStock: (p.stock || 0) > 0,
      stockCount: p.stock || 10,
      tags: p.tags,
      createdAt: p.createdAt,
    };
  }

  private formatCategoryName(name: string): string {
    return name
      .split('-')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
      .join(' ');
  }

  private getCategoryImage(name: string): string {
    const images: Record<string, string> = {
      'smartphones': 'https://images.unsplash.com/photo-1511707171634-5f2ff1b6d790?w=400&h=300&fit=crop',
      'laptops': 'https://images.unsplash.com/photo-1496181133206-80ce9b88a853?w=400&h=300&fit=crop',
      'fragrances': 'https://images.unsplash.com/photo-1541647280916-45aceca3239b?w=400&h=300&fit=crop',
      'skincare': 'https://images.unsplash.com/photo-1596462502278-27bfdc403348?w=400&h=300&fit=crop',
      'groceries': 'https://images.unsplash.com/photo-1542838132-92c53300491e?w=400&h=300&fit=crop',
      'home-decoration': 'https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?w=400&h=300&fit=crop',
      'furniture': 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=400&h=300&fit=crop',
      'tops': 'https://images.unsplash.com/photo-1434389677669-e08b4cac3105?w=400&h=300&fit=crop',
      'womens-dresses': 'https://images.unsplash.com/photo-1595777457583-95e059d581b8?w=400&h=300&fit=crop',
      'womens-shoes': 'https://images.unsplash.com/photo-1543163521-1bf539c55dd2?w=400&h=300&fit=crop',
      'mens-shirts': 'https://images.unsplash.com/photo-1490578474895-699cd4e2cf59?w=400&h=300&fit=crop',
      'mens-shoes': 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400&h=300&fit=crop',
      'mens-watches': 'https://images.unsplash.com/photo-1524592094714-0f0654e20314?w=400&h=300&fit=crop',
      'womens-watches': 'https://images.unsplash.com/photo-1524592094714-0f0654e20314?w=400&h=300&fit=crop',
      'womens-bags': 'https://images.unsplash.com/photo-1584917865442-de89df76afd3?w=400&h=300&fit=crop',
      'womens-jewellery': 'https://images.unsplash.com/photo-1515562141207-7a88fb7ce338?w=400&h=300&fit=crop',
      'sunglasses': 'https://images.unsplash.com/photo-1511499767150-a48a237f0083?w=400&h=300&fit=crop',
      'automotive': 'https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?w=400&h=300&fit=crop',
      'motorcycle': 'https://images.unsplash.com/photo-1558981403-c5f9899a28bc?w=400&h=300&fit=crop',
      'lighting': 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=300&fit=crop',
    };
    return images[name] || 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=400&h=300&fit=crop';
  }
}

class AuthService {
  private users: User[] = [
    {
      id: '1',
      email: 'demo@shopverse.com',
      name: 'Demo User',
      avatar: undefined,
      addresses: [
        {
          id: '1',
          firstName: 'Demo',
          lastName: 'User',
          street: '123 Main Street',
          city: 'San Francisco',
          state: 'CA',
          zipCode: '94102',
          country: 'United States',
          phone: '+1 (555) 123-4567',
          isDefault: true,
        },
      ],
      createdAt: new Date().toISOString(),
    },
  ];

  async login(email: string, password: string): Promise<{ user: User; token: string }> {
    await new Promise(resolve => setTimeout(resolve, 500));

    const user = this.users.find(u => u.email === email);
    if (user && password.length >= 6) {
      return {
        user,
        token: `mock-jwt-token-${Date.now()}`,
      };
    }
    throw new Error('Invalid email or password');
  }

  async register(name: string, email: string, password: string): Promise<{ user: User; token: string }> {
    await new Promise(resolve => setTimeout(resolve, 500));

    const existingUser = this.users.find(u => u.email === email);
    if (existingUser) {
      throw new Error('Email already registered');
    }

    const newUser: User = {
      id: String(Date.now()),
      email,
      name,
      addresses: [],
      createdAt: new Date().toISOString(),
    };
    this.users.push(newUser);

    return {
      user: newUser,
      token: `mock-jwt-token-${Date.now()}`,
    };
  }

  async getMe(token: string): Promise<User | null> {
    await new Promise(resolve => setTimeout(resolve, 300));

    if (token.startsWith('mock-jwt-token')) {
      return this.users[0];
    }
    return null;
  }
}

class OrderService {
  private orders: Order[] = [];

  async createOrder(items: CartItem[], shippingAddress: any, paymentMethod: string): Promise<Order> {
    await new Promise(resolve => setTimeout(resolve, 500));

    const subtotal = items.reduce((sum, item) => sum + item.product.price * item.quantity, 0);
    const shipping = subtotal > 50 ? 0 : 5.99;
    const tax = subtotal * 0.0875;
    const total = subtotal + shipping + tax;

    const order: Order = {
      id: `ORD-${Date.now().toString(36).toUpperCase()}`,
      items,
      subtotal,
      shipping,
      tax,
      total,
      shippingAddress,
      paymentMethod,
      status: 'pending',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    this.orders.push(order);
    return order;
  }

  async getOrders(userId: string): Promise<Order[]> {
    await new Promise(resolve => setTimeout(resolve, 300));
    return this.orders.filter(o => o.shippingAddress.firstName);
  }

  async getOrder(orderId: string): Promise<Order | null> {
    await new Promise(resolve => setTimeout(resolve, 200));
    return this.orders.find(o => o.id === orderId) || null;
  }
}

