  logout: () => void;
  clearError: () => void;
  updateUser: (updates: Partial<User>) => void;
  addAddress: (address: Address) => void;
  removeAddress: (addressId: string) => void;
  setDefaultAddress: (addressId: string) => void;
}

export const useAuthStore = create<AuthStore>()(
  persist(
    (set, get) => ({
      user: null,
      token: null,
      isLoading: false,
      error: null,

      login: async (email: string, password: string) => {
        set({ isLoading: true, error: null });
        try {
          const { user, token } = await authService.login(email, password);
          set({ user, token, isLoading: false });
        } catch (error) {
          set({
            error: error instanceof Error ? error.message : 'Login failed',
            isLoading: false,
          });
          throw error;
        }
      },

      register: async (name: string, email: string, password: string) => {
        set({ isLoading: true, error: null });
        try {
          const { user, token } = await authService.register(name, email, password);
          set({ user, token, isLoading: false });
        } catch (error) {
          set({
            error: error instanceof Error ? error.message : 'Registration failed',
            isLoading: false,
          });
          throw error;
        }
      },

      logout: () => {
        set({ user: null, token: null, error: null });
      },

      clearError: () => set({ error: null }),

      updateUser: (updates: Partial<User>) => {
        set((state) => ({
          user: state.user ? { ...state.user, ...updates } : null,
        }));
      },

      addAddress: (address: Address) => {
        set((state) => ({
          user: state.user
            ? {
                ...state.user,
                addresses: [...state.user.addresses, address],
              }
            : null,
        }));
      },

      removeAddress: (addressId: string) => {
        set((state) => ({
          user: state.user
            ? {
                ...state.user,
                addresses: state.user.addresses.filter((a) => a.id !== addressId),
              }
            : null,
        }));
      },

      setDefaultAddress: (addressId: string) => {
        set((state) => ({
          user: state.user
            ? {
                ...state.user,
                addresses: state.user.addresses.map((a) => ({
                  ...a,
                  isDefault: a.id === addressId,
                })),
              }
            : null,
        }));
      },
    }),
    {
      name: 'shopverse-auth',
      partialize: (state) => ({ user: state.user, token: state.token }),
    }
  )
);

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Product } from '@/types';

interface RecentlyViewedStore {
  products: Product[];
  addProduct: (product: Product) => void;
  clearHistory: () => void;
}

export const useRecentlyViewedStore = create<RecentlyViewedStore>()(
  persist(
    (set, get) => ({
      products: [],

      addProduct: (product: Product) => {
        set((state) => {
          const filtered = state.products.filter(p => p.id !== product.id);
          return {
            products: [product, ...filtered].slice(0, 10),
          };
        });
      },

      clearHistory: () => set({ products: [] }),
    }),
    {
      name: 'shopverse-recently-viewed',
      partialize: (state) => ({ products: state.products }),
    }
  )
);
